#!/bin/bash

# Check if password policy is already set to require uppercase letters
if grep -qE 'pam_pwquality.so retry=3 minlen=8 difok=3 ucredit=-1' /etc/pam.d/system-auth; then
    echo "Password policy already configured."
else
    # Update the system-auth file with the new password policy
    sed -i '/^password\s*required\s*pam_pwquality.so/ {
        s/^password\s*required\s*pam_pwquality.so.*/password required pam_pwquality.so retry=3 minlen=8 difok=3 ucredit=-1/;
    }' /etc/pam.d/system-auth
fi

# Apply the changes and ensure they persist across reboots
systemctl restart authselect

#!/bin/bash

# Set minimum password age to 1 day (86400 seconds)
passwd -d 86400

#!/bin/bash

for user in $(awk -F: '{if ($3 > 500) print $1}' /etc/passwd); do
    homedir=$(eval echo ~$user)
    find "$homedir" -type f ! -name ".*" -exec chmod 700 {} \; -o -type d ! -name ".*" -exec chmod 750 {} \;
done
